using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.StartsWith("(800)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.EndsWith("1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
        Assert.AreEqual("digits", ex.ParamName);
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.Contains("Smith", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  Leading Spaces  ", "leading-spaces")]
    [DataRow("UPPER CASE", "upper-case")]
    [DataRow("Multiple   Spaces", "multiple-spaces")]
    [DataRow("Special!@#Characters", "special-characters")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_MixedContent_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post #1!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_SimpleTitle_DoesNotStartOrEndWithDash()
    {
        var result = _formatter.GenerateSlug("--Hello World--");

        Assert.StartsWith("h", result);
        Assert.EndsWith("d", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsExactFormat()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        Assert.Contains("-", result);
        Assert.AreEqual("$-5.50", result);
    }
}

